    solution: { approach: "Bellman-Ford (k+1 iterations)", steps: ["prices = [∞] × n; prices[src]=0","For i in 1..k+1: temp = prices.copy()","For each flight [u,v,w]: if prices[u]+w < temp[v]: temp[v]=prices[u]+w","prices = temp","Return prices[dst] if ≠ ∞ else -1"], time: "O(k × E)", space: "O(V)" },
