    pushback: { challenge: "What if nodes have duplicate values and you need to identify nodes by value, not reference?", options: ["Values alone can't identify nodes in a graph with duplicates. Must use node reference (pointer/identity) as HashMap key. Values are metadata, not identity.","Use value as key","Sort nodes by value"], correct: 0, explanation: "Node identity = reference in memory, not value. HashMap keyed by node reference (not val) correctly handles duplicate values. If two different nodes have val=1, they are separate nodes." },
    followup: { question: "What if you want to serialize the graph to a string and deserialize it later?", options: ["BFS serialization: encode each node's val and neighbor vals as adjacency list. Deserialize by rebuilding from the adjacency list. O(V+E) each direction.","Can't serialize cyclic graphs","Only trees can be serialized"], correct: 0, explanation: "Serialize: BFS, for each node output 'val:[neighbor1_val,neighbor2_val,...]'. Deserialize: parse strings, create nodes, then wire neighbors using a val→node map. O(V+E) both ways. Handle duplicate values by using node IDs." },
    solution: { approach: "DFS with HashMap (original → clone)", steps: ["if node null: return null","if node in map: return map[node]","clone = new Node(node.val)","map[node] = clone","for neighbor in node.neighbors: clone.neighbors.append(dfs(neighbor))","return clone"], time: "O(V+E)", space: "O(V)" },
